def _nombres_fotos_modulos(html):
    """Muestra el primer nombre del docente debajo de su foto en los módulos
    (letra pequeña). El gerente (Vélez) muestra 'Juan Pablo'. Toca el flyMap
    (agrega name), el flyList (lo propaga) y el template (etiqueta + envoltura
    en columna). Idempotente."""

    if 'fl.name' in html:
        print("  [info] nombres en fotos de módulos: ya estaban aplicados")
        return html

    cambios = 0

    # 1) flyMap: agregar 'name' a cada entrada (primer nombre; Vélez -> Juan Pablo)
    fm_old = ("const flyMap = { '01': [{ from: 'Jord', photo: fabPhoto }], "
              "'02': [{ from: 'Vélez', photo: juanPhoto }], "
              "'03': [{ from: 'Forero', photo: andresPhoto }], "
              "'04': [{ from: 'Cort', photo: johanaPhoto }, "
              "{ from: 'Vélez', photo: juanPhoto }], "
              "'05': [{ from: 'Malag', photo: ednaPhoto }, "
              "{ from: 'Vélez', photo: juanPhoto }], "
              "'06': [{ from: 'Fonseca', photo: dianaPhoto }] };")
    fm_new = ("const flyMap = { '01': [{ from: 'Jord', photo: fabPhoto, name: 'Fabian' }], "
              "'02': [{ from: 'Vélez', photo: juanPhoto, name: 'Juan Pablo' }], "
              "'03': [{ from: 'Forero', photo: andresPhoto, name: 'Andrés' }], "
              "'04': [{ from: 'Cort', photo: johanaPhoto, name: 'Johana' }, "
              "{ from: 'Vélez', photo: juanPhoto, name: 'Juan Pablo' }], "
              "'05': [{ from: 'Malag', photo: ednaPhoto, name: 'Edna' }, "
              "{ from: 'Vélez', photo: juanPhoto, name: 'Juan Pablo' }], "
              "'06': [{ from: 'Fonseca', photo: dianaPhoto, name: 'Diana' }] };")
    if fm_old in html:
        html = html.replace(fm_old, fm_new, 1)
        cambios += 1

    # 2) flyList: propagar el name
    fl_old = ("p.flyList = arr.map((x, ix) => ({ from: x.from, "
              "key: p.num + '-' + ix, img: mkFly(x.photo) }));")
    fl_new = ("p.flyList = arr.map((x, ix) => ({ from: x.from, name: x.name, "
              "key: p.num + '-' + ix, img: mkFly(x.photo) }));")
    if fl_old in html:
        html = html.replace(fl_old, fl_new, 1)
        cambios += 1

    # 3) Template: envolver el avatar + nombre en una columna (cada item del
    #    sc-for queda como columna: foto arriba, nombre debajo).
    tpl_old = ('<sc-for list=\\"{{ item.flyList }}\\" as=\\"fl\\" '
               'hint-placeholder-count=\\"1\\"><div data-fly=\\"{{ fl.from }}\\" '
               'style=\\"width:56px; height:56px; border-radius:50%; padding:3px;')
    tpl_new = ('<sc-for list=\\"{{ item.flyList }}\\" as=\\"fl\\" '
               'hint-placeholder-count=\\"1\\">'
               '<div data-flycol=\\"\\" style=\\"display:flex; '
               'flex-direction:column; align-items:center; gap:2px;\\">'
               '<div data-fly=\\"{{ fl.from }}\\" '
               'style=\\"width:56px; height:56px; border-radius:50%; padding:3px;')
    if tpl_old in html:
        html = html.replace(tpl_old, tpl_new, 1)
        cambios += 1

    # cerrar el wrapper de columna tras el nombre y poner el nombre debajo.
    cierre_old = ('cubic-bezier(.34,1.56,.64,1);\\">{{ fl.img }}<\\u002Fdiv>'
                  '<\\u002Fsc-for>')
    cierre_new = ('cubic-bezier(.34,1.56,.64,1);\\">{{ fl.img }}<\\u002Fdiv>'
                  '<span style=\\"font-size:9.5px; font-weight:700; '
                  'color:#3a4250; text-align:center; line-height:1.1; '
                  'max-width:62px; white-space:nowrap; overflow:hidden; '
                  'text-overflow:ellipsis; opacity:0; '
                  'transition:opacity .4s ease;\\">{{ fl.name }}<\\u002Fspan>'
                  '<\\u002Fdiv><\\u002Fsc-for>')
    if cierre_old in html:
        html = html.replace(cierre_old, cierre_new, 1)
        cambios += 1

    # 4) JS: al revelar la foto, revelar también su nombre (el hermano siguiente).
    reveal_old = ("target.style.opacity = '1';\\n            "
                  "target.style.transform = 'scale(1)';")
    reveal_new = ("target.style.opacity = '1';\\n            "
                  "target.style.transform = 'scale(1)';\\n            "
                  "if (target.nextElementSibling) "
                  "target.nextElementSibling.style.opacity = '1';")
    if reveal_old in html:
        html = html.replace(reveal_old, reveal_new, 1)
        cambios += 1

    if cambios >= 5:
        print("  [ok] primer nombre del docente bajo cada foto de los módulos")
    else:
        print(f"  [!!] nombres en fotos: solo {cambios}/5 cambios")
    return html


