def _compactar_modulos(html):
    """Compacta los módulos 1-6: tarjetas más cuadradas/compactas, alineadas al
    tope, sin estirarse para igualar la altura de la columna de Recursos. El
    grid de módulos tenía 'height:100%' + filas '1fr', lo que estiraba las 6
    tarjetas a lo alto (se veían alargadas). Aquí se alinea al tope, las filas
    pasan a 'auto' y cada tarjeta toma un aspect-ratio fijo. Idempotente."""

    if '/* modcompact */' in html:
        print("  [info] módulos: ya estaban compactados")
        return html

    cambios = 0

    # 1) data-mod-grid: quitar height:100%, alinear al tope, filas 'auto'.
    mg_old = ('data-mod-grid=\\"\\" style=\\"grid-column:1; '
              'grid-row:2; display:grid; '
              'grid-template-columns:repeat(3,minmax(0,1fr)); '
              'grid-template-rows:repeat(2,1fr); gap:14px; height:100%;\\">')
    mg_new = ('data-mod-grid=\\"\\" style=\\"grid-column:1; '
              'grid-row:2; align-self:start; display:grid; '
              'grid-template-columns:repeat(3,minmax(0,1fr)); '
              'grid-template-rows:repeat(2,auto); gap:14px; '
              '/* modcompact */\\">')
    if mg_old in html:
        html = html.replace(mg_old, mg_new, 1)
        cambios += 1

    # 2) Cada tarjeta: aspect-ratio fijo (compacta y uniforme) en vez de estirar.
    card_old = ('data-modcard=\\"1\\" style=\\"position:relative; '
                'z-index:{{ item.z }}; --r:30px; display:flex; '
                'flex-direction:column; --mc:{{ item.color }}; '
                'background:var(--base); border-radius:30px; '
                'box-shadow:var(--raise); padding:16px 16px 16px; '
                'transition:box-shadow .28s ease, transform .28s ease; '
                'cursor:pointer; user-select:none;\\"')
    card_new = ('data-modcard=\\"1\\" style=\\"position:relative; '
                'z-index:{{ item.z }}; --r:30px; display:flex; '
                'flex-direction:column; aspect-ratio:1.25 \\u002F 1; '
                'min-height:0; --mc:{{ item.color }}; '
                'background:var(--base); border-radius:30px; '
                'box-shadow:var(--raise); padding:16px 16px 16px; '
                'transition:box-shadow .28s ease, transform .28s ease; '
                'cursor:pointer; user-select:none;\\"')
    if card_old in html:
        html = html.replace(card_old, card_new, 1)
        cambios += 1

    # 3) Responsive: en 2 columnas / celular, relajar el aspect-ratio.
    media_anchor = ('[data-mod-grid] { grid-template-columns: '
                    'repeat(2,minmax(0,1fr)) !important; '
                    'grid-template-rows: none !important; height: auto !important; }')
    media_new = (media_anchor +
                 '\\n  [data-mod-grid] [data-modcard] { aspect-ratio: auto !important; '
                 'min-height: 150px !important; }')
    if media_anchor in html and '[data-modcard] { aspect-ratio: auto' not in html:
        html = html.replace(media_anchor, media_new, 1)
        cambios += 1

    if cambios:
        print(f"  [ok] módulos compactados ({cambios} cambios)")
    else:
        print("  [!!] módulos: no se hallaron los anclajes esperados")
    return html


def _div_balanceado(html, start):
    """(ini, fin) del <div...> que abre en 'start', balanceando tokens
    escapados <div / <\\u002Fdiv>. 'start' apunta al '<' de '<div'."""
    import re
    depth = 0
    for m in re.finditer(r'<div\b|<\\u002Fdiv>', html[start:]):
        if m.group(0) == '<div':
            depth += 1
        else:
            depth -= 1
            if depth == 0:
                return (start, start + m.end())
    return (start, len(html))


def _subir_docentes_cronograma(html):
    """Sube Docentes al hueco bajo los módulos (columna izquierda, agrandado y
    sin scroll interno, con los 6 docentes visibles) y Cronograma al hueco bajo
    el Mapa (columna derecha). Mueve ambos del lower-grid a una 3a fila del
    pg-grid. Idempotente."""

    CLOSE = '<\\u002Fdiv>'

    if '/* lifted2 */' in html:
        print("  [info] subir Docentes/Cronograma: ya estaba aplicado")
        return html

    # 1) lower-grid (con su wrapper data-flat)
    lw = html.find('<div data-flat=\\"\\" data-lower-grid=\\"\\"')
    if lw < 0:
        print("  [!!] subir Docentes/Cronograma: no se halló lower-grid")
        return html
    lw_ini, lw_fin = _div_balanceado(html, lw)
    lower = html[lw_ini:lw_fin]

    # 2) Docentes (data-mobi="3")
    d_rel = lower.find('<div data-mobi=\\"3\\"')
    if d_rel < 0:
        print("  [!!] subir Docentes/Cronograma: no se halló Docentes")
        return html
    d_ini, d_fin = _div_balanceado(lower, d_rel)
    docentes = lower[d_ini:d_fin]

    # 3) Cronograma (segundo hijo del lower-grid)
    c_rel = lower.find('<div', d_fin)
    if c_rel < 0:
        print("  [!!] subir Docentes/Cronograma: no se halló Cronograma")
        return html
    c_ini, c_fin = _div_balanceado(lower, c_rel)
    crono = lower[c_ini:c_fin]

    # 4) AGRANDAR Docentes: quitar scroll interno + overflow + align-self para
    #    que los 6 docentes se vean completos y la card llene el hueco a lo ancho.
    docentes = docentes.replace(
        'gap:10px; max-height:360px; overflow-y:auto; padding:4px 10px 6px 4px;',
        'gap:12px; padding:4px 4px 6px 4px;', 1)
    docentes = docentes.replace(
        'flex-direction:column; overflow:hidden;\\">',
        'flex-direction:column;\\">', 1)
    docentes = docentes.replace(
        'padding:26px 26px 22px; align-self:flex-start; display:flex;',
        'padding:26px 26px 22px; display:flex;', 1)

    # 5) pg-grid -> 3 filas
    pg_old = ('data-pg-grid=\\"\\" style=\\"display:grid; '
              'grid-template-columns:minmax(0,2.15fr) minmax(0,1fr); '
              'grid-template-rows:auto 1fr; gap:18px 18px; align-items:start; '
              'margin-bottom:22px;\\">')
    pg_new = ('data-pg-grid=\\"\\" style=\\"display:grid; '
              'grid-template-columns:minmax(0,2.15fr) minmax(0,1fr); '
              'grid-template-rows:auto auto auto; gap:18px 18px; '
              'align-items:start; margin-bottom:22px; /* lifted2 */\\">')
    if pg_old not in html:
        print("  [!!] subir Docentes/Cronograma: no se halló pg-grid")
        return html
    html = html.replace(pg_old, pg_new, 1)

    # 6) Wrappers de grid. Llevan data-flat para que en móvil (display:contents)
    #    sean transparentes y Docentes/Cronograma conserven su orden acordado.
    doc_wrap = ('<div data-doclift=\\"\\" data-flat=\\"\\" style=\\"grid-column:1; '
                'grid-row:3; min-width:0; display:flex; flex-direction:column;\\">'
                + docentes + CLOSE)
    crono_wrap = ('<div data-cronolift=\\"\\" data-flat=\\"\\" style=\\"grid-column:2; '
                  'grid-row:3; min-width:0; display:flex; flex-direction:column;\\">'
                  + crono + CLOSE)

    # 7) Insertar al final del pg-grid (antes de su cierre)
    pg_open = html.find('data-pg-grid=\\"\\" style')
    pg_bi = html.rfind('<div', 0, pg_open)
    _, pg_bf = _div_balanceado(html, pg_bi)
    ins = pg_bf - len(CLOSE)
    html = html[:ins] + doc_wrap + crono_wrap + html[ins:]

    # 8) Eliminar el lower-grid original (con su comentario si está pegado)
    lw2 = html.find('<div data-flat=\\"\\" data-lower-grid=\\"\\"')
    if lw2 >= 0:
        a, b = _div_balanceado(html, lw2)
        pre = html.rfind('<!-- LOWER GRID -->', 0, a)
        cut = pre if (pre >= 0 and a - pre < 40) else a
        html = html[:cut] + html[b:]

    # 9) Responsive: en celular ambos wrappers a 1 columna y orden natural
    cm = '[data-pg-grid] { grid-template-columns: 1fr !important; }'
    cm2 = (cm + '\\n  [data-doclift], [data-cronolift] { grid-column: 1 !important; '
           'grid-row: auto !important; }')
    if cm in html and '[data-doclift], [data-cronolift]' not in html:
        html = html.replace(cm, cm2, 1)

    print("  [ok] Docentes (agrandado) y Cronograma subidos al hueco (fila 3)")
    return html


def _ampliar_recursos(html):
    """Extiende la tarjeta de 'Recursos' hacia ABAJO para cubrir el espacio
    vacío que queda entre Recursos y el Mapa en la columna derecha. NO mueve ni
    corre nada: solo sube la altura máxima de la lista scrolleable (408px) para
    que la tarjeta crezca y llene el hueco. Idempotente."""

    if '/* recext */' in html or 'max-height:560px' in html:
        print("  [info] ampliar Recursos: ya estaba aplicado")
        return html

    # La lista scrolleable de Recursos tiene 'max-height:408px'. Subirla para que
    # la tarjeta aproveche el alto disponible. Se ancla SOLO al fragmento de
    # estilo (no a atributos previos como data-scrollvis, que otra función pudo
    # haber insertado antes). Idempotente vía la guarda 'data-recext' de arriba…
    # pero como aquí no añadimos atributo, marcamos con un comentario CSS.
    ancla = ('overflow-y:auto; max-height:408px; padding:14px 14px; '
             'border-radius:14px; box-shadow:var(--inset);')
    nuevo = ('overflow-y:auto; max-height:560px; padding:14px 14px; '
             'border-radius:14px; box-shadow:var(--inset); /* recext */')
    if ancla in html:
        html = html.replace(ancla, nuevo, 1)
        print("  [ok] Recursos extendido hacia abajo (lista 408px -> 560px)")
    elif '/* recext */' in html or 'max-height:560px' in html:
        print("  [info] ampliar Recursos: ya tenía la altura ampliada")
    else:
        print("  [info] ampliar Recursos: no se halló la lista de Recursos")
    return html


def _quitar_infografias(html):
    """Elimina por completo el código de las infografías ocultas (ya inactivas):
    (1) el bloque de datos/procesamiento en JS (objeto 'infografias', sus
    handlers .dl, el bucle infoMap) -> se reemplaza por un objeto vacío para no
    romper las referencias; (2) el panel modal 'infoSel' del template (la UI que
    podría mostrarse). Tras esto no queda nada de infografías que se pueda
    activar. Idempotente."""

    import re
    quitados = 0

    # Guarda de idempotencia: si el panel ya no está y el objeto está vacío.
    if ('{{ infoSel }}' not in html) and ('const infografias = {};' in html):
        print("  [info] infografías: ya estaban eliminadas")
        return html

    # (1) Bloque JS: desde 'const infografias = {' hasta 'const infoSel ='
    js_ini = html.find('const infografias = {')
    js_fin = html.find('const infoSel = this.state.infoId ? '
                        'infografias[this.state.infoId] : null;')
    if js_ini >= 0 and js_fin > js_ini and 'const infografias = {};' not in html:
        html = (html[:js_ini] + 'const infografias = {};\\n    '
                + html[js_fin:])
        quitados += 1

    # (2) Panel template: el sc-if value="{{ infoSel }}" completo (balanceado)
    p_ini = html.find('<sc-if value=\\"{{ infoSel }}\\"')
    if p_ini >= 0:
        depth = 0
        p_fin = None
        for m in re.finditer(r'<sc-if\b|<\\u002Fsc-if>', html[p_ini:p_ini + 14000]):
            if m.group(0) == '<sc-if':
                depth += 1
            else:
                depth -= 1
                if depth == 0:
                    p_fin = p_ini + m.end()
                    break
        if p_fin:
            html = html[:p_ini] + html[p_fin:]
            quitados += 1

    if quitados == 2:
        print("  [ok] infografías ocultas eliminadas (JS + panel)")
    elif quitados == 1:
        print("  [ok] infografías: una parte eliminada (revisar la otra)")
    else:
        print("  [info] infografías: ya estaban eliminadas o no se hallaron")
    return html


def _pulso_dias(html):
    """Da un efecto continuo (latido suave de brillo) a los días clicables de la
    jornada (20-25) en el cronograma, para que se note que se puede dar clic.
    Añade animation al estilo de la celda activa no seleccionada y define el
    keyframe. Idempotente."""

    if 'pulseDia' in html:
        print("  [info] pulso de días: ya estaba aplicado")
        return html

    # Añadir animation al estilo del día clicable.
    ancla = ("cursor: 'pointer', background: 'var(--base)', color: cfg.color, "
             "boxShadow: 'var(--raise)' }")
    nuevo = ("cursor: 'pointer', background: 'var(--base)', color: cfg.color, "
             "boxShadow: 'var(--raise)', animation: 'pulseDia 2.4s ease-in-out "
             "infinite' }")
    if ancla in html:
        html = html.replace(ancla, nuevo, 1)

    # Keyframe del latido (brillo de color que aparece y desaparece).
    kf_ancla = ('@keyframes febor-shine-text { 0% { background-position: 0% 50%; } '
                '100% { background-position: 200% 50%; } }')
    if kf_ancla in html and '@keyframes pulseDia' not in html:
        kf = (kf_ancla +
              '\\n@keyframes pulseDia { 0%,100% { box-shadow:var(--raise); } '
              '50% { box-shadow:0 4px 14px rgba(47,123,224,.35), var(--raise); } }')
        html = html.replace(kf_ancla, kf, 1)
        print("  [ok] pulso continuo en los días clicables del cronograma")
    else:
        print("  [info] pulso de días: keyframe ya existía o no se halló")
    return html


def _quitar_puntos_dias(html):
    """Quita los puntitos de color que aparecían debajo de los números de los
    días de la jornada (20-25) en el cronograma. Eran un span decorativo dentro
    de cada celda activa del calendario; se elimina y queda solo el número.
    Idempotente."""

    punto = ("React.createElement('span', { key: 'd', style: { position: "
             "'absolute', bottom: '5px', width: '5px', height: '5px', "
             "borderRadius: '50%', background: cfg.color } }),")
    if punto in html:
        html = html.replace(punto, "", 1)
        print("  [ok] puntos de los días del cronograma quitados")
    else:
        print("  [info] puntos de los días: ya estaban quitados o no se hallaron")
    return html


def _fondo_animado(html):
    """Fondo con destellos blancos pequeños (tipo partículas/estrellas) que
    titilan suave y continuamente detrás de los cuadros. Tenue y tranquilo, solo
    decorativo (pointer-events:none), detrás de todo. Idempotente."""

    if 'data-fondo-anim' in html:
        print("  [info] fondo animado: ya estaba aplicado")
        return html

    # 1) El contenedor raíz necesita position:relative y overflow:hidden.
    ancla_estilo = '--cardmin:200px;'
    if ancla_estilo in html:
        html = html.replace(
            ancla_estilo,
            '--cardmin:200px; position:relative; overflow:hidden;', 1)

    # 2) Generar muchos destellos blancos en posiciones pseudoaleatorias.
    import random
    rnd = random.Random(7)   # semilla fija -> resultado idéntico cada corrida
    chispas = []
    for i in range(46):
        x = round(rnd.uniform(1, 99), 1)
        y = round(rnd.uniform(1, 99), 1)
        tam = round(rnd.uniform(2, 4.5), 1)         # px
        dur = round(rnd.uniform(2.8, 6.5), 1)       # s (titileo)
        delay = round(rnd.uniform(0, 6), 1)         # s
        op = round(rnd.uniform(.35, .8), 2)         # brillo máx
        chispas.append(
            '<div style=\\"position:absolute; left:' + str(x) + '%; top:' + str(y)
            + '%; width:' + str(tam) + 'px; height:' + str(tam) + 'px; '
            'border-radius:50%; background:#ffffff; '
            'box-shadow:0 0 ' + str(round(tam * 2, 1)) + 'px rgba(255,255,255,.9); '
            '--op:' + str(op) + '; opacity:0; '
            'animation:chispa ' + str(dur) + 's ease-in-out ' + str(delay)
            + 's infinite;\\"><\\u002Fdiv>')

    capa = ('\\">\\n  <div data-fondo-anim=\\"\\" aria-hidden=\\"true\\" '
            'style=\\"position:absolute; inset:0; z-index:0; overflow:hidden; '
            'pointer-events:none;\\">' + ''.join(chispas)
            + '<\\u002Fdiv>\\n\\n  <!-- HEADER -->')
    ancla_header = '\\">\\n\\n  <!-- HEADER -->'
    if ancla_header in html:
        html = html.replace(ancla_header, capa, 1)

    # 3) Keyframe del titileo (aparecer y desaparecer suave).
    kf_ancla = ('@keyframes febor-shine-text { 0% { background-position: 0% 50%; } '
                '100% { background-position: 200% 50%; } }')
    if kf_ancla in html and '@keyframes chispa' not in html:
        kf = (kf_ancla +
              '\\n@keyframes chispa { 0%,100% { opacity:0; transform:scale(.6); } '
              '50% { opacity:var(--op); transform:scale(1); } }')
        html = html.replace(kf_ancla, kf, 1)

    print("  [ok] fondo con destellos blancos agregado")
    return html


def _reorganizar_mapa(html):
    """Despeja el visor del Mapa del lugar: quita la insignia 'Vista 360°' y
    saca los dos botones (Google Maps y pantalla completa) de ENCIMA del tour,
    poniéndolos en una fila limpia DEBAJO del visor. Así el tour 360° se ve sin
    elementos propios encima. (Los controles internos del tour son de panorapp
    y no se pueden tocar.) Idempotente."""

    if 'data-maprow' in html:
        print("  [info] reorganización del mapa: ya estaba aplicada")
        return html

    # 1) Quitar la insignia 'Vista 360° en vivo'
    insignia = ('<div style=\\"position:absolute; top:15px; left:15px; '
                'display:flex; align-items:center; gap:7px; '
                'background:rgba(255,255,255,.85); backdrop-filter:blur(6px); '
                'padding:6px 11px; border-radius:30px; font-size:11px; '
                'font-weight:700; color:#2c3e52; box-shadow:0 2px 7px '
                'rgba(0,0,0,.14);\\">\\n            <span style=\\"width:8px; '
                'height:8px; border-radius:50%; background:#2bb673; '
                'box-shadow:0 0 0 3px rgba(43,182,115,.25);\\"><\\u002Fspan>'
                'Vista 360° en vivo\\n          <\\u002Fdiv>\\n          ')
    if insignia in html:
        html = html.replace(insignia, '', 1)

    # 2) Quitar los botones de ENCIMA del visor (overlay absolute)
    i = html.find('<div style=\\"position:absolute; top:13px; right:13px; '
                  'display:flex; gap:8px;\\">')
    if i >= 0:
        fin = html.find('{{ icoExpand }}<\\u002Fa>\\n          <\\u002Fdiv>', i)
        if fin >= 0:
            fin += len('{{ icoExpand }}<\\u002Fa>\\n          <\\u002Fdiv>')
            html = html[:i] + html[fin:]

    # 3) Insertar una fila limpia de botones DEBAJO del visor (antes del info)
    info_anchor = ('<div style=\\"margin-top:15px; display:flex; '
                   'flex-direction:column; gap:11px; font-size:12.5px; '
                   'color:var(--muted);\\">')
    fila = (
        '<div data-maprow=\\"\\" style=\\"margin-top:14px; display:flex; '
        'gap:10px; flex-wrap:wrap;\\">'
        '<a href=\\"https://maps.app.goo.gl/RfNBkPRYtGgqfAZf7\\" target=\\"_blank\\" '
        'rel=\\"noopener\\" style=\\"flex:1; min-width:150px; display:flex; '
        'align-items:center; justify-content:center; gap:8px; padding:11px 14px; '
        'border-radius:13px; background:var(--base); box-shadow:var(--raise); '
        'color:#2bb673; font-weight:700; font-size:13px; text-decoration:none;\\" '
        'style-active=\\"box-shadow:var(--inset);\\">{{ icoMap }} Ver en Google Maps'
        '<\\u002Fa>'
        '<a href=\\"https://360.panorapp.com/colsubsidio/alcaravan/\\" '
        'target=\\"_blank\\" rel=\\"noopener\\" style=\\"flex:1; min-width:150px; '
        'display:flex; align-items:center; justify-content:center; gap:8px; '
        'padding:11px 14px; border-radius:13px; background:var(--base); '
        'box-shadow:var(--raise); color:#2c3e52; font-weight:700; font-size:13px; '
        'text-decoration:none;\\" style-active=\\"box-shadow:var(--inset);\\">'
        '{{ icoExpand }} Pantalla completa<\\u002Fa>'
        '<\\u002Fdiv>\\n        ')
    if info_anchor in html:
        html = html.replace(info_anchor, fila + info_anchor, 1)
        print("  [ok] mapa reorganizado (insignia fuera, botones en fila inferior)")
    else:
        print("  [!!] reorganización del mapa: no se halló el punto de inserción")
    return html


def _ocultar_pantalla_carga(html):
    """Pantalla de carga: reemplaza la 'F' por el logo de Febor (sin recuadro
    de fondo) y oculta el aviso 'Unpacking...'. El logo va embebido en base64
    (LOGO_FEBOR_B64), centrado sobre el fondo claro, mientras el bundle
    desempaqueta. Idempotente."""

    cambios = 0

    # Ocultar solo el aviso 'Unpacking...'
    loading_css = ("#__bundler_loading { position: fixed; bottom: 20px; "
                   "right: 20px;")
    if loading_css in html and "#__bundler_loading { display: none" not in html:
        html = html.replace(
            loading_css,
            "#__bundler_loading { display: none !important; position: fixed; "
            "bottom: 20px; right: 20px;", 1)
        cambios += 1

    # Asegurar que el thumbnail SÍ se vea (revertir el display:none si quedó)
    if "#__bundler_thumbnail { display: none !important; position: fixed;" in html:
        html = html.replace(
            "#__bundler_thumbnail { display: none !important; position: fixed;",
            "#__bundler_thumbnail { position: fixed;", 1)

    # Reemplazar el contenido (SVG con la F) por el logo embebido.
    svg_old = ('<div id="__bundler_thumbnail">\n'
               '<svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg">\n'
               '<rect width="100" height="100" rx="20" fill="#e9ecf1"></rect>\n'
               '<rect x="30" y="30" width="40" height="40" rx="12" '
               'fill="#e9ecf1" stroke="#c7cbd3" stroke-width="2"></rect>\n'
               '<text x="50" y="60" font-family="Manrope,sans-serif" '
               'font-size="26" font-weight="800" fill="#33a06b" '
               'text-anchor="middle">F</text>\n'
               '</svg>\n'
               '</div>')
    # Usar el MISMO logo del encabezado (Jornada de inmersión 2026) para la
    # pantalla de carga, en vez del logo simple de Febor.
    logo_new = ('<div id="__bundler_thumbnail">'
                '<img src="data:image/png;base64,' + HEADER_IMG_B64 + '" '
                'alt="Jornada de inmersion 2026" '
                'style="max-width:min(80%,460px); height:auto; '
                'object-fit:contain;">'
                '</div>')
    if svg_old in html:
        html = html.replace(svg_old, logo_new, 1)
        cambios += 1
    else:
        # El thumbnail ya trae una imagen embebida. Localizar el base64 del
        # PRIMER thumbnail (aparece justo tras <body>) y, si es el logo simple
        # de Febor, cambiarlo por el de la Jornada 2026.
        ti = html.find('__bundler_thumbnail')
        bi = html.find('base64,', ti)
        if ti != -1 and bi != -1:
            bi += len('base64,')
            actual = html[bi:bi + 60]
            if actual == LOGO_FEBOR_B64[:60]:
                html = html.replace(LOGO_FEBOR_B64, HEADER_IMG_B64, 1)
                cambios += 1
            # si actual == HEADER_IMG_B64[:60] ya estaba puesto (idempotente)

    if cambios:
        print("  [ok] pantalla de carga con logo Febor (sin fondo)")
    else:
        print("  [info] pantalla de carga: ya tenía el logo o no se halló")
    return html


def _tinte_modulos(html):
    """Da a la zona superior de cada módulo un tinte suave de SU propio color
    (armonía), en vez del gris neutro. Cada tarjeta ya tiene una capa
    'background:var(--mc); opacity:.045' (casi imperceptible) y un velo blanco
    encima; se sube un poco el tinte de color y se suaviza el velo para que el
    color se note de forma elegante. Idempotente."""

    if "opacity:.13" in html and "modtint-done" in html:
        print("  [info] tinte de módulos: ya estaba aplicado")
        return html

    cambios = 0
    # Subir el tinte de color de la tarjeta (.045 -> .13)
    tinte_old = 'background:var(--mc); opacity:.045;'
    tinte_new = 'background:var(--mc); opacity:.13;'
    if tinte_old in html:
        html = html.replace(tinte_old, tinte_new, 1)
        cambios += 1

    # Suavizar el velo blanco para que el color se asome
    velo_old = ('background:linear-gradient(135deg, rgba(255,255,255,.5), '
                'rgba(255,255,255,.34));')
    velo_new = ('background:linear-gradient(135deg, rgba(255,255,255,.40), '
                'rgba(255,255,255,.24)); /* modtint-done */')
    if velo_old in html:
        html = html.replace(velo_old, velo_new, 1)
        cambios += 1

    if cambios == 2:
        print("  [ok] tinte suave de color aplicado a los módulos")
    else:
        print(f"  [!!] tinte de módulos: solo {cambios}/2 cambios")
    return html


def _barra_scroll_movil(html):
    """Barra de desplazamiento SIEMPRE visible en celular para Recursos y
    Docentes. iOS oculta la barra nativa pase lo que pase, así que se crea una
    barra propia (overlay) con JavaScript: un riel + un indicador que está
    siempre presente y se mueve al deslizar. Solo se activa en móvil (<=600px).
    Idempotente."""

    if 'data-scrollvis' not in html:
        # marcar las listas (por si no estaban marcadas)
        doc_ancla = ('data-scroll=\\"\\" style=\\"display:grid; '
                     'grid-template-columns:repeat(auto-fit,minmax(min(100%,180px),1fr)); '
                     'gap:10px; max-height:360px; overflow-y:auto;')
        rec_ancla = ('data-scroll=\\"\\" style=\\"overflow-y:auto; max-height:408px; '
                     'padding:14px 14px; border-radius:14px; box-shadow:var(--inset);')
        for ancla in [doc_ancla, rec_ancla]:
            if ancla in html:
                html = html.replace(
                    ancla, ancla.replace('data-scroll=\\"\\"',
                                         'data-scroll=\\"\\" data-scrollvis=\\"\\"', 1), 1)

    if 'feborScrollbars' in html:
        print("  [info] barra de scroll móvil (JS): ya estaba aplicada")
        return html

    # Script de barra personalizada SIEMPRE visible (una sola línea, sin saltos).
    js = (
        "<script>(function(){function feborScrollbars(){"
        "if(window.innerWidth>600)return;"
        "var ls=document.querySelectorAll('[data-scrollvis]');"
        "ls.forEach(function(el){"
        "if(el.__fsb)return; el.__fsb=true;"
        "el.style.scrollbarWidth='none';"
        "el.style.position=el.style.position||'relative';"
        "var par=el;"
        "if(getComputedStyle(par).position==='static'){par.style.position='relative';}"
        "var track=document.createElement('div');"
        "track.style.cssText='position:absolute;top:6px;bottom:6px;right:3px;width:7px;"
        "border-radius:6px;background:rgba(120,130,150,.16);z-index:50;pointer-events:none;';"
        "var thumb=document.createElement('div');"
        "thumb.style.cssText='position:absolute;left:0;width:7px;border-radius:6px;"
        "background:linear-gradient(180deg,#22d3a8,#1bb59f 40%,#2f7be0 75%,#7a5cc7);"
        "background-size:100% 240%;box-shadow:0 0 7px rgba(43,181,159,.6);"
        "transition:top .05s linear;animation:scrollFlow 3.5s ease-in-out infinite;';"
        "track.appendChild(thumb);"
        "var host=el.parentNode;"
        "if(getComputedStyle(host).position==='static'){host.style.position='relative';}"
        "host.appendChild(track);"
        "function upd(){"
        "var sh=el.scrollHeight,ch=el.clientHeight;"
        "if(sh<=ch+2){track.style.display='none';return;}track.style.display='block';"
        "var th=Math.max(28,ch*ch/sh);"
        "var tr=track.clientHeight;"
        "var max=el.scrollTop/(sh-ch);"
        "thumb.style.height=th+'px';"
        "thumb.style.top=(max*(tr-th))+'px';}"
        "el.addEventListener('scroll',upd,{passive:true});"
        "if(window.ResizeObserver){new ResizeObserver(upd).observe(el);}"
        "setTimeout(upd,60);setTimeout(upd,400);upd();"
        "});}"
        "var t=setInterval(feborScrollbars,500);"
        "setTimeout(function(){clearInterval(t);},6000);"
        "window.addEventListener('resize',feborScrollbars);"
        "document.addEventListener('DOMContentLoaded',feborScrollbars);"
        "feborScrollbars();})();<\\u002Fscript>"
    )
    ancla = '<\\u002Fscript>\\n\\n\\n<\\u002Fbody><\\u002Fhtml>'
    nuevo = '<\\u002Fscript>\\n' + js + '\\n\\n<\\u002Fbody><\\u002Fhtml>'
    if ancla in html:
        html = html.replace(ancla, nuevo, 1)
        print("  [ok] barra de scroll SIEMPRE visible en móvil (JS, Recursos y Docentes)")
    else:
        print("  [!!] barra de scroll móvil: no se halló el punto de inserción")
    return html


def _animar_burbujas(html):
    """Agrega animaciones a las burbujas de términos del asistente:
    - Entrada: aparecen con un 'pop' escalonado (cascada) al abrir el asistente.
    - Selección: al hacer clic, la burbuja activa hace un rebote/pulso.
    Toca el JS (agrega delay y anim por burbuja), el template (animation inline)
    y la CSS (keyframes). Idempotente."""

    if "bubbleIn" in html:
        print("  [info] animación de burbujas: ya estaba aplicada")
        return html

    cambios = 0

    # 1) JS: añadir delay escalonado y la animación (distinta si está activa).
    js_ancla = ("return { w: g.w, label, size: (13 + t * 15).toFixed(1) + 'px', "
                "op: (0.55 + t * 0.45).toFixed(2), active, fg, bgc, pick: () =>")
    js_nuevo = ("var __d = (gi % 24) * 0.035; "
                "var __anim = active ? 'bubblePop .45s cubic-bezier(.34,1.56,.64,1) both' "
                ": ('bubbleIn .42s cubic-bezier(.34,1.56,.64,1) ' + __d.toFixed(3) + 's both'); "
                "return { w: g.w, label, size: (13 + t * 15).toFixed(1) + 'px', "
                "op: (0.55 + t * 0.45).toFixed(2), active, fg, bgc, anim: __anim, pick: () =>")
    if js_ancla in html:
        html = html.replace(js_ancla, js_nuevo, 1)
        cambios += 1

    # 2) Template: agregar animation:{{ b.anim }} a la burbuja.
    tpl_ancla = ('font-size:{{ b.size }}; transition:transform .15s ease;\\" '
                 'style-hover=\\"transform:translateY(-2px);\\" '
                 'style-active=\\"box-shadow:var(--inset);\\">{{ b.label }}')
    tpl_nuevo = ('font-size:{{ b.size }}; transition:transform .15s ease; '
                 'animation:{{ b.anim }};\\" '
                 'style-hover=\\"transform:translateY(-2px);\\" '
                 'style-active=\\"box-shadow:var(--inset);\\">{{ b.label }}')
    if tpl_ancla in html:
        html = html.replace(tpl_ancla, tpl_nuevo, 1)
        cambios += 1

    # 3) CSS: keyframes de entrada (pop) y de selección (rebote).
    kf_ancla = ('@keyframes febor-shine-text { 0% { background-position: 0% 50%; } '
                '100% { background-position: 200% 50%; } }')
    kf_nuevo = (kf_ancla +
                '\\n@keyframes bubbleIn { 0% { opacity:0; transform:scale(.5) '
                'translateY(8px); } 60% { opacity:1; transform:scale(1.08); } '
                '100% { opacity:1; transform:scale(1) translateY(0); } }'
                '\\n@keyframes bubblePop { 0% { transform:scale(1); } '
                '35% { transform:scale(1.22) rotate(-3deg); } '
                '65% { transform:scale(.94) rotate(2deg); } '
                '100% { transform:scale(1) rotate(0); } }'
                '\\n@keyframes scrollFlow { 0% { background-position:50% 0%; } '
                '50% { background-position:50% 100%; } '
                '100% { background-position:50% 0%; } }')
    if kf_ancla in html:
        html = html.replace(kf_ancla, kf_nuevo, 1)
        cambios += 1

    if cambios == 3:
        print("  [ok] animación de burbujas agregada (entrada + selección)")
    else:
        print(f"  [!!] animación de burbujas: solo {cambios}/3 cambios")
    return html


def _agregar_pagina_snippets(html):
    """Agrega el número de página a cada resultado del buscador. El índice
    ahora incluye 'pages' (offsets de fin de página por documento); aquí se
    calcula, para cada coincidencia, en qué página cae y se antepone una
    etiqueta 'Pág. N' al fragmento. Idempotente."""

    if "snippetPagina" in html:
        print("  [info] número de página en resultados: ya estaba aplicado")
        return html

    ancla = ("return React.createElement('span', null, pre, "
             "React.createElement('mark', { style: { background: '#fde68a', "
             "color: '#1b2330', borderRadius: '3px', padding: '0 2px', "
             "fontWeight: 700 } }, mid), post);")

    nuevo = (
        "var snippetPagina = 0; "
        "try { var __pg = doc.pages; if (__pg && __pg.length) { "
        "while (snippetPagina < __pg.length && p >= __pg[snippetPagina]) snippetPagina++; "
        "snippetPagina = snippetPagina + 1; } } catch (_) { snippetPagina = 0; } "
        "var __chip = snippetPagina ? React.createElement('span', "
        "{ style: { display: 'inline-block', background: '#eaf2fe', color: "
        "'#2f7be0', borderRadius: '20px', padding: '1px 9px', fontSize: '11px', "
        "fontWeight: 800, marginRight: '8px', whiteSpace: 'nowrap', "
        "verticalAlign: 'middle' } }, 'Pág. ' + snippetPagina) : null; "
        "return React.createElement('span', null, __chip, pre, "
        "React.createElement('mark', { style: { background: '#fde68a', "
        "color: '#1b2330', borderRadius: '3px', padding: '0 2px', "
        "fontWeight: 700 } }, mid), post);"
    )

    if ancla in html:
        html = html.replace(ancla, nuevo, 1)
        print("  [ok] número de página agregado a los resultados del buscador")
    else:
        print("  [info] número de página: no se halló el punto de inserción")
    return html


def _reordenar_movil(html):
    """Reordena las secciones SOLO en celular (<=600px), sin alterar el diseño
    de escritorio. Orden en móvil:
       Mapa -> Cronograma -> Docentes -> Módulos -> Recursos -> Certificado.
    El contenedor raíz se vuelve flex en columna y TODOS los contenedores
    intermedios (pg-grid, lower-grid, el wrapper de cronograma+certificado y el
    de la columna derecha del mapa) pasan a display:contents para que cada
    sección sea hija directa del flujo y su 'order' funcione. Idempotente."""

    if 'data-mobiroot' in html:
        print("  [info] reordenamiento móvil: ya estaba aplicado")
        return html

    # 1) Contenedor RAÍZ (único)
    raiz = '<div style=\\"min-height:100vh; --base:#e9ecf1;'
    if raiz in html:
        html = html.replace(raiz, '<div data-mobiroot=\\"\\" ' + raiz[5:], 1)
    else:
        print("  [!!] reordenamiento móvil: no se halló el contenedor raíz.")
        return html

    # 2) Marcar TODOS los contenedores intermedios a aplanar (data-flat).
    flats = [
        '<div data-pg-grid=\\"\\"',
        '<div data-lower-grid=\\"\\"',
        # wrapper que agrupa Cronograma + Certificado
        ('<div style=\\"display:flex; flex-direction:column; gap:18px; '
         'align-self:flex-start;\\">'),
        # wrapper de la columna derecha (Mapa)
        ('<div style=\\"display:flex; flex-direction:column; gap:24px; '
         'height:100%;\\">'),
    ]
    for ancla in flats:
        if ancla in html:
            html = html.replace(ancla, '<div data-flat=\\"\\" ' + ancla[5:], 1)

    # 3) Etiquetar cada SECCIÓN (la tarjeta real) con data-mobi (order).
    # Módulos = mod-grid (order 4)
    if '<div data-mod-grid=\\"\\"' in html:
        html = html.replace('<div data-mod-grid=\\"\\"',
                            '<div data-mobi=\\"4\\" data-mod-grid=\\"\\"', 1)
    # Recursos (panel) = order 5
    rec_ancla = ('<div style=\\"background:var(--base); border-radius:var(--r); '
                 'box-shadow:var(--raise); padding:22px; display:flex; flex-d')
    if rec_ancla in html:
        html = html.replace(rec_ancla, '<div data-mobi=\\"5\\" ' + rec_ancla[5:], 1)
    # Docentes(3), Cronograma(2), Certificado(6), Mapa(1):
    # se etiqueta la PRIMERA tarjeta tras cada comentario.
    for com, orden in [
        ('<!-- DOCENTES -->',              '3'),
        ('<!-- CERTIFICADO -->',           '6'),
        ('<!-- MAPA -->',                  '1'),
    ]:
        pos = html.find(com)
        if pos < 0:
            continue
        divpos = html.find('<div ', pos)
        if divpos < 0:
            continue
        html = (html[:divpos] + '<div data-mobi=\\"' + orden + '\\" '
                + html[divpos + 5:])

    # Cronograma: tras el comentario va el wrapper (ya marcado data-flat) y luego
    # la tarjeta real -> etiquetar la SEGUNDA apertura de div (la tarjeta).
    pos = html.find('<!-- CRONOGRAMA + CLAUSURA -->')
    if pos >= 0:
        d1 = html.find('<div ', pos)            # wrapper (data-flat)
        d2 = html.find('<div ', d1 + 5)         # tarjeta cronograma
        if d2 >= 0:
            html = (html[:d2] + '<div data-mobi=\\"2\\" ' + html[d2 + 5:])

    # 4) CSS dentro de la media query de 600px, scoping al contenedor raíz.
    ancla_media = ('@media (max-width: 600px) {\\n  [data-mod-grid] '
                   '{ grid-template-columns: 1fr !important; }\\n  '
                   '[data-lower-grid] { grid-template-columns: 1fr !important; }')
    if ancla_media in html and 'data-mobi-css' not in html:
        css = (ancla_media + '\\n  /* data-mobi-css */\\n'
               '  [data-mobiroot] { display:flex !important; '
               'flex-direction:column !important; }\\n'
               '  [data-mobiroot] [data-flat] { display:contents !important; }\\n'
               '  [data-mobiroot] [data-mobi=\\"1\\"] { order:1 !important; }\\n'
               '  [data-mobiroot] [data-mobi=\\"2\\"] { order:2 !important; }\\n'
               '  [data-mobiroot] [data-mobi=\\"3\\"] { order:3 !important; }\\n'
               '  [data-mobiroot] [data-mobi=\\"4\\"] { order:4 !important; }\\n'
               '  [data-mobiroot] [data-mobi=\\"5\\"] { order:5 !important; }\\n'
               '  [data-mobiroot] [data-mobi=\\"6\\"] { order:6 !important; }\\n'
               '  [data-mobiroot] [data-mobi] { width:100% !important; '
               'align-self:stretch !important; box-sizing:border-box !important; }\\n'
               '  [data-mod-grid] { gap:26px !important; }\\n'
               '  [data-mobiroot] [data-mobi], [data-mod-grid] > * { '
               'margin-bottom:6px !important; }')
        html = html.replace(ancla_media, css, 1)

    print("  [ok] secciones reordenadas para celular "
          "(mapa, cronograma, docentes, módulos, recursos, certificado)")
    return html


def _mejorar_movil(html):
    """Mejoras para la vista en celular:
    1) Agrega el meta viewport (esencial: sin él, el móvil muestra todo
       diminuto a ancho de escritorio).
    2) Reduce el padding lateral de los contenedores principales en pantallas
       pequeñas (32px aprieta demasiado en un teléfono).
    Idempotente."""
    cambios = 0

    # 1) meta viewport tras el charset (en el <head> externo, no en el bundle)
    charset = '<meta charset="utf-8">'
    viewport = ('<meta charset="utf-8">\n  <meta name="viewport" '
                'content="width=device-width, initial-scale=1">')
    if 'name="viewport"' not in html and charset in html:
        html = html.replace(charset, viewport, 1)
        cambios += 1

    # 2) regla de padding para móvil dentro de la media query existente (600px)
    #    El bloque vive dentro de la cadena JSON del bundle -> usar \\n escapado.
    ancla_media = ('@media (max-width: 600px) {\\n  [data-mod-grid] '
                   '{ grid-template-columns: 1fr !important; }\\n  '
                   '[data-lower-grid] { grid-template-columns: 1fr !important; }')
    if ancla_media in html and "pad-movil-aplicado" not in html:
        regla = (ancla_media + '\\n  /* pad-movil-aplicado */\\n'
                 '  [style*=\\"max-width:1000px\\"] { padding-left:16px '
                 '!important; padding-right:16px !important; }')
        html = html.replace(ancla_media, regla, 1)
        cambios += 1

    if cambios:
        print(f"  [ok] mejoras de vista móvil aplicadas ({cambios})")
    else:
        print("  [info] vista móvil: ya estaba ajustada")
    return html


def _acordeon_resultados(html):
    """Convierte los resultados del asistente documental en un acordeón:
    cada documento aparece colapsado (solo título + N° coincidencias) y al
    hacer clic en la cabecera se despliegan los textos encontrados. Toca el
    JS (agrega 'expanded' y 'toggle' por documento) y el template (cabecera
    clickeable + chevron + envuelve snippets y botón en sc-if). Idempotente."""

    if "r.toggle" in html:
        print("  [info] acordeón de resultados: ya estaba aplicado")
        return html

    cambios = 0

    # --- 1) JS: agregar expanded + toggle a cada entrada de docResults ---
    push_anchor = ("open: () => this.openDocTab({ name: doc.title.replace(/:/g, "
                   "' -')")
    push_nuevo = (
        "expanded: !!(this.state.expandedDocs && this.state.expandedDocs[doc.id]), "
        "notExpanded: !(this.state.expandedDocs && this.state.expandedDocs[doc.id]), "
        "toggle: () => { const m = Object.assign({}, this.state.expandedDocs); "
        "m[doc.id] = !m[doc.id]; this.setState({ expandedDocs: m }); }, "
        "open: () => this.openDocTab({ name: doc.title.replace(/:/g, ' -')"
    )
    if push_anchor in html:
        html = html.replace(push_anchor, push_nuevo, 1)
        cambios += 1

    # --- 2) Template: cabecera clickeable + chevron ---
    header_open = ('<div style=\\"display:flex; align-items:center; gap:12px; '
                   'margin-bottom:9px;\\">')
    header_nuevo = ('<div onclick=\\"{{ r.toggle }}\\" style=\\"display:flex; '
                    'align-items:center; gap:12px; margin-bottom:9px; '
                    'cursor:pointer;\\">')
    if header_open in html:
        html = html.replace(header_open, header_nuevo, 1)
        cambios += 1

    # chevron tras el countLabel (icono según r.expanded / r.notExpanded)
    countlabel_close = '{{ r.countLabel }}<\\u002Fdiv>'
    chevron_cond = (
        '{{ r.countLabel }}<\\u002Fdiv>'
        '<sc-if value=\\"{{ r.expanded }}\\" hint-placeholder-val=\\"{{ false }}\\">'
        '<div style=\\"flex:0 0 auto; width:34px; height:34px; border-radius:50%; '
        'background:#eaf2fe; display:flex; align-items:center; '
        'justify-content:center; color:#2f7be0;\\">'
        '<svg width=\\"22\\" height=\\"22\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" '
        'stroke=\\"currentColor\\" stroke-width=\\"3.5\\" stroke-linecap=\\"round\\" '
        'stroke-linejoin=\\"round\\"><polyline points=\\"6 9 12 15 18 9\\">'
        '<\\u002Fpolyline><\\u002Fsvg><\\u002Fdiv><\\u002Fsc-if>'
        '<sc-if value=\\"{{ r.notExpanded }}\\" hint-placeholder-val=\\"{{ true }}\\">'
        '<div style=\\"flex:0 0 auto; width:34px; height:34px; border-radius:50%; '
        'background:#eef2f7; display:flex; align-items:center; '
        'justify-content:center; color:#2f7be0;\\">'
        '<svg width=\\"22\\" height=\\"22\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" '
        'stroke=\\"currentColor\\" stroke-width=\\"3.5\\" stroke-linecap=\\"round\\" '
        'stroke-linejoin=\\"round\\"><polyline points=\\"9 18 15 12 9 6\\">'
        '<\\u002Fpolyline><\\u002Fsvg><\\u002Fdiv><\\u002Fsc-if>'
    )
    if countlabel_close in html:
        html = html.replace(countlabel_close, chevron_cond, 1)
        cambios += 1

    # --- 3) Template: envolver snippets + botón en sc-if r.expanded ---
    snippets_open = ('<div data-scroll=\\"\\" style=\\"display:flex; '
                     'flex-direction:column; gap:8px; margin-bottom:12px;')
    snippets_nuevo = ('<sc-if value=\\"{{ r.expanded }}\\" '
                      'hint-placeholder-val=\\"{{ false }}\\">'
                      '<div data-scroll=\\"\\" style=\\"display:flex; '
                      'flex-direction:column; gap:8px; margin-bottom:12px;')
    if snippets_open in html:
        html = html.replace(snippets_open, snippets_nuevo, 1)
        cambios += 1

    abrir_btn_end = '{{ icoDown }} Abrir documento<\\u002Fdiv>'
    abrir_nuevo = '{{ icoDown }} Abrir documento<\\u002Fdiv><\\u002Fsc-if>'
    if abrir_btn_end in html:
        html = html.replace(abrir_btn_end, abrir_nuevo, 1)
        cambios += 1

    if cambios == 5:
        print("  [ok] acordeón de resultados aplicado (clic para desplegar)")
    else:
        print(f"  [!!] acordeón: solo {cambios}/5 cambios; revisar anclas")
    return html


def _quitar_scroll_doble(html):
    """Elimina la doble barra de desplazamiento del asistente de documentos.
    El panel del asistente (contenedor fijo) ya tiene su propio scroll; además,
    la lista interna de resultados tenía 'max-height + overflow-y:auto', lo que
    creaba una segunda barra pegada a la primera. Se le quita el scroll propio
    a la lista interna para que fluya y solo se desplace el panel. Idempotente."""
    target = ("display:flex; flex-direction:column; gap:8px; margin-bottom:12px; "
              "max-height:340px; overflow-y:auto; padding-right:6px; "
              "scrollbar-width:auto; scrollbar-color:#1bb59f transparent;")
    nuevo = ("display:flex; flex-direction:column; gap:8px; margin-bottom:12px; "
             "padding-right:6px;")
    if target in html:
        html = html.replace(target, nuevo, 1)
        print("  [ok] doble barra de desplazamiento corregida (asistente)")
    elif nuevo in html:
        print("  [info] doble barra: ya estaba corregida")
    else:
        print("  [info] doble barra: no se halló el contenedor interno")
    return html


def _quitar_botones_info(html):
    """Quita los botones circulares de información (ⓘ) que aparecían en las
    tarjetas de la Circular Contable. Esos botones solo se renderizan cuando
    a un item se le asigna '.info', cosa que hace un bucle con infoMap. Al
    dejar el infoMap vacío, ningún item recibe '.info' y el botón (que está
    bajo un sc-if value="{{ r.info }}") deja de aparecer. Idempotente."""
    target = "const infoMap = ['t1', 't2', 't3', 't4', 't5'];"
    if target in html:
        html = html.replace(target, "const infoMap = [];", 1)
        print("  [ok] botones de información (ⓘ) quitados de las tarjetas")
    elif "const infoMap = [];" in html:
        print("  [info] botones de información: ya estaban quitados")
    else:
        print("  [info] botones de información: no se halló el infoMap")
    return html


def _quitar_modulo3_velez(html):
    """Quita 'Módulo 3: Marco Legal' SOLO de la lista de temas de Juan Pablo
    Vélez. Se elimina la entrada con su coma final (que es exclusiva de su
    array, en medio de la lista); el docente dueño del Módulo 3 no se toca.
    Idempotente."""
    entrada = "'Módulo 3: Marco Legal: Reglas Claves para Actuar con Seguridad', "
    if entrada in html:
        html = html.replace(entrada, "", 1)
        print("  [ok] 'Módulo 3' quitado de los temas de Juan Pablo Vélez")
    else:
        print("  [info] 'Módulo 3' en Vélez: ya estaba quitado o no se halló")
    return html


def _esc_js(s):
    return s.replace("\\", "\\\\").replace("'", "\\'")


def _items_js_de_seccion(sec, items):
    """Construye el string JS del arreglo de items para una sección."""
    js = []
    for it in items:
        name = _esc_js(it["name"])
        fname = _esc_js(it["fname"])
        key = _esc_js(it["key"])
        js.append(
            "{ lead: this.fileBadge('PDF', '" + sec["color"] + "'), name: '" + name +
            "', meta: '" + sec["meta"] + "', tail: RI.down, action: () => "
            "this.openDocTab({ name: '" + name + "', fname: '" + fname +
            "', b64: (JSON.parse(atob(this." + sec["mapavar"] + "))['" + key + "']) }) }"
        )
    return ", ".join(js)


def _reemplazar_items_grupo(html, grupo_title, items_str):
    """Reemplaza el arreglo items: [...] de un grupo existente, contando
    corchetes balanceados (soporta corchetes anidados)."""
    marcador = grupo_title + "', icon: RI."
    pos = html.find(marcador)
    if pos < 0:
        return html, False
    pos_items = html.find("items: ", pos)
    if pos_items < 0:
        return html, False
    ini = html.find("[", pos_items)
    if ini < 0:
        return html, False
    depth, fin = 0, -1
    for k in range(ini, len(html)):
        if html[k] == "[":
            depth += 1
        elif html[k] == "]":
            depth -= 1
            if depth == 0:
                fin = k
                break
    if fin < 0:
        return html, False
    return html[:ini] + "[" + items_str + "]" + html[fin + 1:], True


def _inyectar_secciones(html, secciones_data):
    """Inyecta TODAS las secciones documentales dinámicas:
    - embebe el mapa base64 de cada sección como variable JS,
    - reemplaza/crea el arreglo items de cada grupo en recGroups.
    secciones_data: lista de (sec, items, files_b64).
    """
    SEP = "\\n  "  # separador ESCAPADO (texto barra+n), no salto real

    # ancla estable para insertar variables: la última var b64 conocida.
    m_anchor = re.search(r"(eticaB64 = '[A-Za-z0-9+/=]*';)", html)
    if not m_anchor:
        print("  [!!] no se encontró ancla para variables; se omite secciones.")
        return html
    ancla = m_anchor.group(1)

    bloque_vars = ""
    for sec, items, files_b64 in secciones_data:
        # 1) variable del mapa de archivos (idempotente: quitar previa)
        html = re.sub(
            r"(\\n  )?\s*" + re.escape(sec["mapavar"]) + r" = '[A-Za-z0-9+/=]*';",
            "", html,
        )
        mapa_b64 = base64.b64encode(
            json.dumps(files_b64, ensure_ascii=False).encode("utf-8")
        ).decode("ascii")
        bloque_vars += SEP + sec["mapavar"] + " = '" + mapa_b64 + "';"

    # insertar todas las variables juntas tras el ancla
    html = html.replace(ancla, ancla + bloque_vars, 1)

    # 2) items por grupo
    for sec, items, files_b64 in secciones_data:
        items_str = _items_js_de_seccion(sec, items)

        if sec.get("nuevo"):
            # crear el grupo nuevo ANTES del grupo indicado
            destino = sec["antes_de"]
            pos = html.find(destino + "', icon: RI.")
            if pos < 0:
                print(f"  [!!] no se pudo ubicar '{destino}' para crear "
                      f"'{sec['grupo']}'; se omite.")
                continue
            # retroceder hasta el '{' que abre ese grupo destino
            ini_grupo = html.rfind("{ title:", 0, pos)
            if ini_grupo < 0:
                print(f"  [!!] no se halló inicio del grupo destino; se omite "
                      f"'{sec['grupo']}'.")
                continue
            nuevo_grupo = (
                "{ title: '" + _esc_js(sec["grupo"]) +
                "', icon: RI.folder, items: [" + items_str + "] },\\n      "
            )
            # evitar duplicar si ya existe
            if (sec["grupo"] + "', icon: RI.") in html:
                html, ok = _reemplazar_items_grupo(html, sec["grupo"], items_str)
                print(f"  [ok] '{sec['grupo']}' actualizada ({len(items)} docs)")
            else:
                html = html[:ini_grupo] + nuevo_grupo + html[ini_grupo:]
                print(f"  [ok] '{sec['grupo']}' creada ({len(items)} docs)")
        else:
            html, ok = _reemplazar_items_grupo(html, sec["grupo"], items_str)
            estado = f"actualizada ({len(items)} docs)" if ok else "NO encontrada"
            print(f"  [{'ok' if ok else '!!'}] '{sec['grupo']}' {estado}")

    return html


def _emparejar_grid_dom(html):
    """Reequilibra el grid principal para eliminar los espacios muertos:
      · Envuelve LOGO + MÓDULOS en un mismo stack (col 1, fila 1) -> arrancan
        juntos arriba, sin el salto entre el logo y los módulos.
      · DOCENTES pasa a col 1, fila 2.
      · Mete CRONOGRAMA + CERTIFICADO DENTRO del rightstack (Recursos + Mapa),
        de modo que toda la columna derecha sea UN solo stack que estira a lo
        alto; Recursos crece (flex:1) y el resto queda encadenado sin saltos.
      · pg-grid pasa a 2 filas con align-items:stretch.
    Reutiliza el helper _div_balanceado. Idempotente."""

    CLOSE = '<\\u002Fdiv>'
    if '/* gridfit-dom */' in html:
        print("  [info] emparejar (DOM): ya estaba aplicado")
        return html

    hl = html.find('<div data-hdrlogo=\\"\\"')
    if hl < 0:
        print("  [!!] emparejar (DOM): no se halló hdrlogo")
        return html
    hl_end = html.find(CLOSE, hl) + len(CLOSE)
    logo = html[hl:hl_end]
    # Centrar el logo horizontalmente dentro de su contenedor (que abarca el
    # ancho de los 3 módulos), de modo que quede sobre el módulo central (2).
    logo = logo.replace(
        'justify-content:flex-start; align-items:flex-start;',
        'justify-content:center; align-items:center;', 1)

    mg = html.find('data-mod-grid=\\"\\"')
    mg = html.rfind('<div', 0, mg)
    mg_s, mg_e = _div_balanceado(html, mg)
    mods = html[mg_s:mg_e]

    rs = html.find('<div data-rightstack=\\"\\"')
    rs_s, rs_e = _div_balanceado(html, rs)
    rs_block = html[rs_s:rs_e]
    rs_inner = rs_block[rs_block.find('>') + 1 : -len(CLOSE)]

    dl = html.find('<div data-doclift=\\"\\"')
    dl_s, dl_e = _div_balanceado(html, dl)
    dl_block = html[dl_s:dl_e]
    dl_inner = dl_block[dl_block.find('>') + 1 : -len(CLOSE)]

    cl = html.find('<div data-cronolift=\\"\\"')
    cl_s, cl_e = _div_balanceado(html, cl)
    cl_block = html[cl_s:cl_e]
    cl_inner = cl_block[cl_block.find('>') + 1 : -len(CLOSE)]

    if min(hl, mg_s, rs_s, dl_s, cl_s) < 0:
        print("  [!!] emparejar (DOM): falta algún bloque, se omite")
        return html

    # Docentes: pasar el grid interno de 'auto-fit' (que dejaba 5+1 con un hueco
    # grande junto al último) a 3 columnas fijas -> 6 docentes quedan 3+3, en dos
    # filas parejas y compactas. Solo cambia el reparto del grid (no contenido).
    dl_inner = dl_inner.replace(
        'grid-template-columns:repeat(auto-fit,minmax(min(100%,180px),1fr)); '
        'gap:12px; padding:4px 4px 6px 4px;',
        'grid-template-columns:repeat(3,minmax(0,1fr)); '
        'gap:12px; padding:4px 4px 6px 4px;', 1)

    # Columna izquierda: LOGO + MÓDULOS + DOCENTES en un único stack vertical,
    # para que fluyan compactos uno tras otro sin huecos entre ellos.
    left_stack = ('<div data-flat=\\"\\" data-lefttop=\\"\\" style=\\"grid-column:1; '
                  'grid-row:1; display:flex; flex-direction:column; gap:18px; '
                  'min-width:0; /* gridfit-dom */\\">'
                  + logo + mods
                  + '<div data-doclift=\\"\\" data-flat=\\"\\" style=\\"min-width:0; '
                    'display:flex; flex-direction:column;\\">' + dl_inner + CLOSE
                  + CLOSE)

    # Cronograma+Certificado: quitar el 'align-self:flex-start' para que el
    # contenedor pueda fluir natural debajo del Mapa, sin empujarlo al fondo
    # (el margin-top:auto generaba un vacío grande entre Mapa y Cronograma).
    cl_inner = cl_inner.replace(
        'display:flex; flex-direction:column; gap:18px; align-self:flex-start;\\">',
        'display:flex; flex-direction:column; gap:18px;\\">', 1)

    # Columna derecha: Recursos + Mapa + Cronograma + Certificado, un solo stack.
    right_stack = ('<div data-rightstack=\\"\\" style=\\"grid-column:2; '
                   'grid-row:1; display:flex; flex-direction:column; '
                   'gap:18px; min-width:0;\\">' + rs_inner + cl_inner + CLOSE)
    # Recursos toma su altura natural; el stack derecho fluye compacto arriba.
    right_stack = right_stack.replace(
        '<div data-mobi=\\"5\\" style=\\"background:var(--base);',
        '<div data-mobi=\\"5\\" style=\\"flex:0 1 auto; min-height:340px; '
        'background:var(--base);', 1)

    # Reemplazos de ATRÁS hacia ADELANTE (hl < mg_s < rs_s < dl_s < cl_s)
    html = html[:cl_s] + html[cl_e:]
    html = html[:dl_s] + html[dl_e:]                # quitar doclift de su sitio
    html = html[:rs_s] + right_stack + html[rs_e:]
    html = html[:mg_s] + html[mg_e:]                # quitar mods de su sitio
    html = html[:hl] + left_stack + html[hl_end:]   # logo+mods+docentes juntos

    import re
    pg = html.find('data-pg-grid=\\"\\" style')
    tag_start = html.rfind('<div', 0, pg)
    tag_end = html.find('>', pg) + 1
    tag = html[tag_start:tag_end]
    newtag = re.sub(r'grid-template-rows:[^;]*;',
                    'grid-template-rows:auto;', tag)
    newtag = newtag.replace('align-items:stretch;', 'align-items:start;')
    html = html[:tag_start] + newtag + html[tag_end:]

    print("  [ok] grid emparejado por DOM (izquierda en un stack; derecha en un stack)")
    return html


def _cronograma_panel_pc(html):
    """En ESCRITORIO, el detalle de un día del cronograma deja de mostrarse como
    ventana emergente vertical (modal) y pasa a un panel HORIZONTAL ancho,
    posicionado de forma ABSOLUTA dentro del contenedor del contenido (no fijo
    al viewport: no sigue el scroll), en la zona vacía izquierda-central, un poco
    corrido a la derecha. El orden del día se reparte en varias columnas. En
    MÓVIL (<=920px) se conserva el popup vertical original sin cambios.

    Solo añade marcadores (data-calwrap/data-calcard/data-calplan/data-calline)
    y un bloque CSS responsive. No toca textos, colores, contenido ni lógica.
    Idempotente.
    """
    if 'cronograma-panel-pc' in html:
        print("  [info] cronograma panel PC: ya estaba aplicado")
        return html

    overlay_anchor = ('<div onclick=\\"{{ closeCal }}\\" style=\\"position:fixed; '
                      'inset:0; background:rgba(38,46,64,.5)')
    card_anchor = ('<div onclick=\\"{{ stop }}\\" style=\\"width:min(440px,100%); '
                   'max-height:86vh; overflow:auto;')
    plan_anchor = ('<div style=\\"position:relative; display:flex; '
                   'flex-direction:column; gap:16px;\\">')
    line_anchor = ('<div style=\\"position:absolute; left:18px; top:10px; '
                   'bottom:10px; width:2px; background:var(--line); '
                   'border-radius:2px;\\"><\\u002Fdiv>')

    if overlay_anchor not in html or card_anchor not in html:
        print("  [info] cronograma panel PC: no se halló el popup, se omite")
        return html

    # 1) Marcadores (sin tocar los estilos inline ni los handlers).
    html = html.replace(
        overlay_anchor,
        '<div data-calwrap=\\"\\" onclick=\\"{{ closeCal }}\\" '
        'style=\\"position:fixed; inset:0; background:rgba(38,46,64,.5)', 1)
    html = html.replace(
        card_anchor,
        '<div data-calcard=\\"\\" onclick=\\"{{ stop }}\\" '
        'style=\\"width:min(440px,100%); max-height:86vh; overflow:auto;', 1)
    # contenedor de la lista del orden del día (para hacerla horizontal)
    html = html.replace(
        plan_anchor,
        '<div data-calplan=\\"\\" style=\\"position:relative; display:flex; '
        'flex-direction:column; gap:16px;\\">', 1)
    # línea vertical decorativa (se oculta en el layout horizontal)
    if line_anchor in html:
        html = html.replace(
            line_anchor,
            '<div data-calline=\\"\\" style=\\"position:absolute; left:18px; '
            'top:10px; bottom:10px; width:2px; background:var(--line); '
            'border-radius:2px;\\"><\\u002Fdiv>', 1)

    # 2) CSS escritorio: el overlay deja de oscurecer/bloquear y se ancla como
    # un panel ABSOLUTO respecto al contenedor del contenido (no al viewport),
    # de modo que NO sigue la pantalla al hacer scroll. Queda en la zona vacía
    # izquierda-central, un poco corrido a la derecha. Lista en columnas.
    css = (
        '/* cronograma-panel-pc */\\n'
        '@media (min-width: 921px) {\\n'
        '  [data-calwrap] {\\n'
        '    position:absolute !important;\\n'
        '    inset:auto !important;\\n'
        '    left:0 !important;\\n'
        '    right:0 !important;\\n'
        '    bottom:clamp(90px, 13vh, 170px) !important;\\n'
        '    top:auto !important;\\n'
        '    background:transparent !important;\\n'
        '    backdrop-filter:none !important;\\n'
        '    -webkit-backdrop-filter:none !important;\\n'
        '    pointer-events:none !important;\\n'
        '    padding:0 clamp(14px, 3.5vw, 30px) !important;\\n'
        '    display:block !important;\\n'
        '    z-index:40 !important;\\n'
        '    animation:none !important;\\n'
        '  }\\n'
        '  [data-calwrap] [data-calcard] {\\n'
        '    pointer-events:auto !important;\\n'
        '    position:relative !important;\\n'
        '    margin-left:clamp(60px, 12vw, 220px) !important;\\n'
        '    margin-right:auto !important;\\n'
        '    width:min(58vw, 720px) !important;\\n'
        '    max-width:calc(67% - 40px) !important;\\n'
        '    max-height:none !important;\\n'
        '    animation:febor-pop .32s cubic-bezier(.2,.9,.3,1.35) !important;\\n'
        '  }\\n'
        '  [data-calwrap] [data-calcard] [data-calplan] {\\n'
        '    display:grid !important;\\n'
        '    grid-template-columns:repeat(2, minmax(0, 1fr)) !important;\\n'
        '    gap:14px 26px !important;\\n'
        '    align-content:start !important;\\n'
        '  }\\n'
        '  [data-calwrap] [data-calcard] [data-calline] {\\n'
        '    display:none !important;\\n'
        '  }\\n'
        '}\\n'
        '@media (min-width: 1280px) {\\n'
        '  [data-calwrap] [data-calcard] [data-calplan] {\\n'
        '    grid-template-columns:repeat(3, minmax(0, 1fr)) !important;\\n'
        '  }\\n'
        '}\\n')

    anchor = '[data-hdrlogo] img { width:min(240px,70%); }\\n'
    if anchor in html:
        html = html.replace(anchor, anchor + css, 1)
    else:
        mq = '@media (max-width: 920px) {\\n  [data-pg-grid]'
        if mq in html:
            html = html.replace(mq, css + mq, 1)
        else:
            html = html.replace('<\\u002Fstyle>', css + '<\\u002Fstyle>', 1)

    print("  [ok] cronograma: panel horizontal ancho (PC), popup vertical en móvil")
    return html


def inyectar_en_html(indice, actas, blobs, secciones_data=None):
    html_path = ROOT / HTML_FILE
    if not html_path.exists():
        sys.exit(f"  [error] no se encontró '{HTML_FILE}' en la carpeta. "
                 "Coloca el HTML del aplicativo junto al script.")

    html = html_path.read_text(encoding="utf-8")

    cambios = []
    html, ok = _reemplazar_asignacion(html, "docIdxB64", _b64(indice))
    cambios.append(("docIdxB64", ok))
    html, ok = _reemplazar_asignacion(html, "actasB64", _b64(actas))
    cambios.append(("actasB64", ok))

    # Poblar TODAS las secciones documentales (dinámicas)
    html = _inyectar_secciones(html, secciones_data or [])

    # Reorganizar la línea de tiempo (diseño más compacto)
    html = _compactar_timeline(html)
    # Compactar el cronograma (calendario)
    html = _compactar_cronograma(html)
    # Quitar el banner rojo '[bundle] error' por recursos externos
    html = _silenciar_errores_recursos(html)
    # Quitar 'Módulo 3' de los temas de Juan Pablo Vélez
    html = _quitar_modulo3_velez(html)
    # Quitar los botones de información (ⓘ) de las tarjetas
    html = _quitar_botones_info(html)
    # Corregir la doble barra de desplazamiento del asistente
    html = _quitar_scroll_doble(html)
    # Acordeón: documentos colapsados, clic para desplegar
    html = _acordeon_resultados(html)
    # Número de página en cada resultado del buscador
    html = _agregar_pagina_snippets(html)
    # Animación de las burbujas (entrada + selección)
    html = _animar_burbujas(html)
    # Barra de scroll visible en móvil (Recursos y Docentes)
    html = _barra_scroll_movil(html)
    # Tinte suave de color en los módulos
    html = _tinte_modulos(html)
    # Ocultar la pantalla de carga (F / Unpacking)
    html = _ocultar_pantalla_carga(html)
    # Reorganizar el Mapa del lugar (despejar el visor)
    html = _reorganizar_mapa(html)
    # Agrandar el visor del tour 360° para que los controles estorben menos
    html = _agrandar_visor_mapa(html)
    # Quitar el panel roto de vista previa de documento
    html = _quitar_preview_doc(html)
    # Cabecera fija del detalle de día en el cronograma
    html = _cabecera_fija_dia(html)
    # Reemplazar el encabezado por la imagen (logo + título)
    html = _header_imagen(html)
    # Fondo animado tenue (orbes suaves)
    html = _fondo_animado(html)
    # Quitar los puntos de los días del cronograma
    html = _quitar_puntos_dias(html)
    # Eliminar por completo las infografías ocultas
    html = _quitar_infografias(html)
    # Bandas de los módulos más delgadas (ícono al lado del título)
    html = _bandas_delgadas(html)
    # Fotos de docentes en los módulos un poco más grandes
    html = _fotos_modulos_grandes(html)
    # Primer nombre del docente debajo de cada foto en los módulos
    html = _nombres_fotos_modulos(html)
    # Pulso continuo en los días clicables del cronograma
    html = _pulso_dias(html)
    # Mejoras para la vista en celular (viewport + padding)
    html = _mejorar_movil(html)
    # Reordenar secciones solo en celular
    html = _reordenar_movil(html)
    # Reacomodar el encabezado (logo sobre módulos, Recursos hasta arriba)
    html = _reacomodar_encabezado(html)
    # Mover el badge de fecha al título del Cronograma
    html = _mover_badge_cronograma(html)
    # Subir el Mapa del lugar debajo de Recursos (aprovechar espacio)
    html = _subir_mapa(html)
    # Compactar los módulos 1-6 (tarjetas menos alargadas, alineadas al tope)
    html = _compactar_modulos(html)
    # Extender Recursos hacia abajo para cubrir el espacio vacío
    html = _ampliar_recursos(html)
    # Subir Docentes (agrandado) y Cronograma al hueco bajo los módulos
    html = _subir_docentes_cronograma(html)
    # Emparejar el grid: cerrar los espacios muertos (logo+módulos juntos,
    # columna derecha en un único stack que estira). Va al final.
    html = _emparejar_grid_dom(html)
    html = _cronograma_panel_pc(html)

    # Escribir el HTML final sobre el mismo archivo (regenera en sitio).
    html_path.write_text(html, encoding="utf-8")

    for var, ok in cambios:
        estado = "actualizado" if ok else "NO encontrado en el HTML (se omitió)"
        print(f"  [{'ok' if ok else '!!'}] {var}: {estado}")
    print(f"  -> {HTML_FILE} generado en la carpeta del proyecto")


# ---------------------------------------------------------------------------
# 6. Publicación a GitHub
# ---------------------------------------------------------------------------
def publicar_github():
    print("\n== Publicando en GitHub ==")
    comandos = [
        ["git", "add", "."],
        ["git", "commit", "-m", "Actualizar buscador documental y actas"],
        ["git", "push"],
    ]
    for cmd in comandos:
        print("  $ " + " ".join(cmd))
        res = subprocess.run(cmd, cwd=str(ROOT), capture_output=True, text=True)
        salida = (res.stdout or "") + (res.stderr or "")
        if salida.strip():
            print("    " + salida.strip().replace("\n", "\n    "))
        if res.returncode != 0 and cmd[1] != "commit":
            print(f"    [aviso] '{cmd[1]}' terminó con código {res.returncode}.")


# ---------------------------------------------------------------------------
# Principal
# ---------------------------------------------------------------------------
def main():
    print(f"Raíz del proyecto: {ROOT}\n")

    print("== 1. Indexando documentos de TODAS las carpetas (dinámico) ==")
    # El índice de búsqueda se construye COMPLETO desde las secciones.
    indice = {"docs": [], "global": []}
    secciones_data = []

    for sec in SECCIONES:
        print(f"\n  -- {sec['grupo']}  ({sec['carpeta']}) --")
        docs, files_b64, items, glob_extra = construir_seccion(sec)
        indice["docs"].extend(docs)
        indice["global"].extend(glob_extra)
        secciones_data.append((sec, items, files_b64))

    # Recortar 'global' a los 44 términos más frecuentes (como el original)
    from collections import Counter as _C
    agg = _C()
    docs_by_word = {}
    for g in indice["global"]:
        agg[g["w"]] += g["n"]
        docs_by_word.setdefault(g["w"], set()).update(g["docs"])
    indice["global"] = [
        {"w": w, "n": n, "docs": sorted(docs_by_word[w])}
        for w, n in agg.most_common(44)
    ]

    print("\n== 4. Leyendo actas del Consejo ==")
    actas = construir_actas()

    print("\n== 5. Inyectando datos en el HTML ==")
    inyectar_en_html(indice, actas, {}, secciones_data)

    publicar_github()

    print("\n[LISTO] Abre el HTML localmente o revisa GitHub Pages.")


if __name__ == "__main__":
    main()
